-- ============================================================
-- منجزات الشباب السعودي — الجداول والمحتوى (سكيمة DATA_CENTER)
-- يُشغَّل مرة واحدة في SQL Workshop → SQL Scripts
-- ============================================================

CREATE TABLE "ACHIEVEMENT_CATEGORIES" (
  "CODE"          VARCHAR2(40) NOT NULL,
  "NAME_AR"       VARCHAR2(200) NOT NULL,
  "ICON"          VARCHAR2(60),
  "COLOR"         VARCHAR2(20),
  "DISPLAY_ORDER" NUMBER DEFAULT 100,
  CONSTRAINT "ACH_CAT_PK" PRIMARY KEY ("CODE")
);

CREATE TABLE "YOUTH_ACHIEVEMENTS" (
  "ID"            NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY,
  "YEAR_NO"       NUMBER DEFAULT 2025 NOT NULL,
  "CATEGORY"      VARCHAR2(40) NOT NULL,
  "TITLE"         VARCHAR2(500) NOT NULL,
  "SUMMARY"       VARCHAR2(4000),
  "FIGURE_VALUE"  VARCHAR2(50),      -- الرقم البارز (يظهر في شريط الأرقام)
  "FIGURE_LABEL"  VARCHAR2(200),     -- وصف الرقم
  "SOURCE_URL"    VARCHAR2(1000),
  "IS_FEATURED"   NUMBER(1) DEFAULT 0,   -- 1 = يظهر في الصفحة الرئيسية
  "DISPLAY_ORDER" NUMBER DEFAULT 100,
  "IS_PUBLISHED"  NUMBER(1) DEFAULT 1,
  "CREATED_AT"    TIMESTAMP DEFAULT SYSTIMESTAMP,
  CONSTRAINT "ACH_PK" PRIMARY KEY ("ID"),
  CONSTRAINT "ACH_CAT_FK" FOREIGN KEY ("CATEGORY") REFERENCES "ACHIEVEMENT_CATEGORIES"("CODE")
);

CREATE INDEX "ACH_YEAR_CAT_IX" ON "YOUTH_ACHIEVEMENTS" ("YEAR_NO","CATEGORY","IS_PUBLISHED");

