-- ---------------- المشاركات الدولية ----------------
INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","IS_FEATURED","DISPLAY_ORDER") VALUES
('international','مشاركة الشباب السعودي في القمة العالمية للشباب 2025',
 'شارك وفد المملكة بقيادة هيئة الاتصالات والفضاء والتقنية في جلسات حوارية تناولت أولويات الشباب والتمكين الرقمي للمرأة القيادية واستكشافات الذكاء الاصطناعي، ضمن مبادرة «توصيل الجيل».',0,10);

INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","IS_FEATURED","DISPLAY_ORDER") VALUES
('international','منتدى الشباب التابع للمجلس الاقتصادي والاجتماعي للأمم المتحدة (ECOSOC) 2025',
 'شارك وفد سعودي في مقر الأمم المتحدة بنيويورك بدعم من مؤسسة «مسك» ضمن برنامج «أصوات عالمية»، وناقش قضايا الاستدامة والابتكار وتعزيز التعاون بين القطاعات.',1,20);

INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","FIGURE_VALUE","FIGURE_LABEL","IS_FEATURED","DISPLAY_ORDER") VALUES
('international','مشاركة الكشافة السعودية في الحدث الكشفي العالمي JOTA-JOTI 2025',
 'مشاركة جمعية الكشافة العربية السعودية في أكبر حدث كشفي رقمي تحت شعار «عالم يشكله الشباب»، بمشاركة أكثر من مليوني شاب من أكثر من 170 دولة.',
 '170+','دولة مشاركة في الحدث الكشفي',0,30);

-- ---------------- المشاركات المحلية والتطوع ----------------
INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","FIGURE_VALUE","FIGURE_LABEL","IS_FEATURED","DISPLAY_ORDER") VALUES
('local','التطوع الشبابي في المملكة',
