 '56 مليون','ساعة تطوعية خلال 3 أشهر',1,10);

INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","FIGURE_VALUE","FIGURE_LABEL","IS_FEATURED","DISPLAY_ORDER") VALUES
('local','تطوع الشباب في خدمة ضيوف الرحمن',
