 '2.1 مليون','ساعة تطوعية في الحج',1,20);

INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","FIGURE_VALUE","FIGURE_LABEL","IS_FEATURED","DISPLAY_ORDER") VALUES
('local','حملة «كلّي فخر» للتطوع الصحي',
 'أطلق مركز التطوع الصحي بوزارة الصحة حملة تحتفي بـ700 ألف متطوع صحي قدّموا 55,319,222 ساعة تطوعية بقيمة اقتصادية بديلة تجاوزت 3.9 مليار ريال، ضمن مستهدف رؤية 2030 للوصول إلى مليون متطوع.',
 '700 ألف','متطوع صحي',0,30);

INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","IS_FEATURED","DISPLAY_ORDER") VALUES
