-- ---------------- الجوائز العالمية ----------------
INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","FIGURE_VALUE","FIGURE_LABEL","IS_FEATURED","DISPLAY_ORDER") VALUES
('awards','23 جائزة للمنتخب السعودي في «آيسف 2025»',
 'حصد المنتخب السعودي للعلوم والهندسة 23 جائزة في معرض ريجينيرون الدولي للعلوم والهندسة بمدينة كولومبوس الأمريكية، بمشاركة أكثر من 1700 طالب من 70 دولة — منها 14 جائزة كبرى و9 جوائز خاصة.',
 '23','جائزة دولية في آيسف 2025',1,10);

INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","FIGURE_VALUE","FIGURE_LABEL","IS_FEATURED","DISPLAY_ORDER") VALUES
('awards','6 جوائز في أولمبياد الرياضيات الدولي',
