-- ---------------- إسهام القطاع غير الربحي — مركز مرشاد ----------------
INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","FIGURE_VALUE","FIGURE_LABEL","IS_FEATURED","DISPLAY_ORDER") VALUES
('nonprofit','مركز مرشاد لبحوث ودراسات الشباب',
 'مركز بحثي متخصص في قضايا الشباب، أنجز خلال 2025 أربعة عشر مشروعًا ودراسة تشمل منهجية البحث العلمي في قضايا الشباب، وتحليل الجهود المبذولة في منظومة الشباب، وفرص التكامل مع برامج رؤية 2030، والتوجهات المؤثرة مستقبلًا، وتصميم المدن الصديقة للشباب، وسن المسؤولية، وطبقات أجيال الشباب، والقيم الأساسية، ومؤشر قضايا الشباب، وموقع المملكة في مؤشرات التنمية الشبابية العالمية.',
 '14','مشروعًا ودراسة في 2025',1,10);

INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","IS_FEATURED","DISPLAY_ORDER") VALUES
('nonprofit','منصة بيانات الشباب التشاركية',
 'منصة تقنية تجمع بيانات شاملة وموحّدة لمنظومة الشباب في المملكة، تخدم المعنيين والمهتمين بالشأن الشبابي — أحد مشاريع مركز مرشاد.',0,20);

INSERT INTO "YOUTH_ACHIEVEMENTS" ("CATEGORY","TITLE","SUMMARY","IS_FEATURED","DISPLAY_ORDER") VALUES
('nonprofit','مؤشر قضايا الشباب',
 'مشروع يسعى إلى بناء أداة لتحليل ورصد القضايا ذات الأولوية للشباب، ويوفّر بيانات دقيقة تساعد في صياغة السياسات واتخاذ القرارات النوعية.',0,30);

